374	    private String buildTransferFeeRule(JSONObject ruleObject, SdfRatioInfoDTO ratioInfo, SdfActivityInfoDTO activityInfoDTO) {
375	        String template = readTransferFeeRuleTemplate(ruleObject, ratioInfo);
376	        int mode = ratioInfo != null && ratioInfo.isSetRatioMode()
377	                ? ratioInfo.getRatioMode() : SdfRatioModeEnum.FIXED.getMode();
378	        if (mode == SdfRatioModeEnum.DYNAMIC.getMode()
379	                && activityInfoDTO.isSetRatioVariable()
380	                && activityInfoDTO.getRatioVariable() != null) {
381	            BigDecimal x = new BigDecimal(activityInfoDTO.getCashRatioDecimal());
382	            BigDecimal y = new BigDecimal(activityInfoDTO.getRatioVariable());
383	            BigDecimal upper = x.add(y);
384	            if (x.compareTo(upper) == 0) {
385	                return String.format(template, x.stripTrailingZeros().toPlainString());
386	            }
387	            return String.format(template, x.stripTrailingZeros().toPlainString(),
388	                    upper.stripTrailingZeros().toPlainString());
389	        }
390	        return String.format(template, activityInfoDTO.getCashRatioDecimal());
391	    }
