450	    public  <T> T getJsonValue(JSONObject jsonObject, String path, Class<T> clazz, T defaultValue) {
451	        try {
452	            if (jsonObject == null || StringUtils.isEmpty(path)) {
453	                return defaultValue;
454	            }
455	            String[] keys = path.split("\\.");
456	            for (int i = 0; i < keys.length - 1; i++) {
457	                String key = keys[i];
458	                if (key.contains(":")) {
459	                    String[] listKeys = key.split(":");
460	                    JSONArray array = jsonObject.getJSONArray(listKeys[0]);
461	                    jsonObject = array.getJSONObject(Integer.parseInt(listKeys[1]));
462	                } else {
463	                    jsonObject = jsonObject.getJSONObject(key);
464	                }
465	                if (jsonObject == null) {
466	                    return defaultValue;
467	                }
468	            }
469	            T result = jsonObject.getObject(keys[keys.length - 1], clazz);
470	            if (result == null) {
471	                return defaultValue;
472	            }
473	            return result;
474	        } catch (Exception e) {
475	            log.error("getJsonValue exception, keyList:{} defaultValue:{}", path, defaultValue);
476	        }
477	        return defaultValue;
478	    }
