555	    /**
556	     * 格式化比例展示：去除多余的尾部零，最少保留小数点后两位。
557	     * 例：2.0000 → 2.00，3.111 → 3.111，3.000 → 3.00
558	     */
559	    private String formatRatio(String ratio) {
560	        if (ratio == null || ratio.isEmpty()) {
561	            return ratio;
562	        }
563	        try {
564	            BigDecimal bd = new BigDecimal(ratio);
565	            int scale = Math.max(2, bd.stripTrailingZeros().scale());
566	            return bd.setScale(scale, RoundingMode.HALF_UP).toPlainString();
567	        } catch (NumberFormatException e) {
568	            return ratio;
569	        }
570	    }
