807	    public boolean terminateSdfRule(long ruleId, int operateType, SdfSignExtraInfo extraInfo) {
808	        String lockKey = "lock_sdf_sign_" + ruleId;
809	        try {
810	            Boolean isLock = kvService.setnxByRedis(lockKey, RedisCategory.COMMON_CATEGORY_TEN_MINUTES, "1", 30);
811	            if (!isLock) {
812	                throw new BusinessRuntimeException("当前协议正在解约中，请稍后重试");
813	            }
814	
815	            RuleOperateInfo operateInfo = new RuleOperateInfo();
816	            BeanUtils.copyProperties(extraInfo, operateInfo);
817	            operateInfo.setOperateType(operateType);
818	            WmAdGmvToAdRule rule = wmKaGmvToAdDomainService.getRuleByRuleId(ruleId);
819	            if (rule == null) {
820	                return true;
821	            }
822	
823	            int ret = wmKaGmvToAdDomainService.closeRule(rule.getRuleId(), operateInfo);
824	            if (ret > 0) {
825	                RuleExtraInfo ruleExtraInfo = JsonUtil.parse(rule.getExtraInfo(), RuleExtraInfo.class);
826	                if (ruleExtraInfo == null) {
827	                    String info = String.format("extraInfo is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
828	                    Cat.logEvent("SDF", "PostActionFail", "1", info);
829	                    log.error("terminateSdfRule error, info:{}", info);
830	                    return true;
831	                }
832	                SdfAdAccountActivity activity = adAccountSdfService.getActivityById(ruleExtraInfo.getActivityConfigId());
833	                if (activity == null) {
834	                    String info = String.format("activity is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
835	                    Cat.logEvent("SDF", "PostActionFail", "1", info);
836	                    log.error("terminateSdfRule error, info:{}", info);
837	                    return true;
838	                }
839	                SdfLaunchStrategy launchStrategy = JsonUtil.parse(activity.getLaunchStrategy(), SdfLaunchStrategy.class);
840	                SdfBenefitRule benefitRule = ruleExtraInfo.getSdfBenefitRule();
841	                SdfCouponInfo couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();
842	
843	                SdfPostActionParam param = new SdfPostActionParam();
844	                param.setSignId(rule.getRuleId());
845	                param.setPartnerId(rule.getToKaAcctId());
846	                param.setPartnerType(getPartnerTypeByTransferType(rule.getTransferType()));
847	                param.setOperateType(operateType);
848	                param.setLaunchStrategy(launchStrategy);
849	                param.setCouponInfo(couponInfo);
850	                param.setExtraInfo(extraInfo);
851	                postAction(param);
852	
853	            }
854	            return ret > 0;
855	        } catch (Exception e) {
856	            log.error("AdAccountSdfAppService.terminateSdfSign is error, ruleId:{} operateType:{}", ruleId, operateType, e);
857	        } finally{
858	            kvService.compareAndDelete(lockKey, "1", RedisCategory.COMMON_CATEGORY_TEN_MINUTES);
859	        }
860	
861	        return false;
862	    }
